1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  priorContracts: number;
4	};
5	
6	export type Item = Record<string, unknown>;
7	
8	export type Policy = {
9	  customer: Customer;
10	  items: Item[];
11	};
12	
13	export type QuoteResult = {
14	  premium: number;
15	};
16	
17	export type ClaimResult = {
18	  payout: number;
19	  remainingCap: number;
20	};
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const basePremiumForItem = (item: Item): number =>
32	  BASE_PREMIUM_BY_ITEM_TYPE[item.type as string] ?? 0;
33	
34	export function quote(policy: Policy): QuoteResult {
35	  const basePremium = policy.items.reduce(
36	    (sum, item) => sum + basePremiumForItem(item),
37	    0,
38	  );
39	  return { premium: basePremium + PROCESSING_FEE };
40	}
41	
42	export function claim(..._args: unknown[]): ClaimResult {
43	  return undefined as unknown as ClaimResult;
44	}
